index 1f58a28ca..b759bfe40 100644
--- a/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js
+++ b/packages/svelte/src/compiler/phases/2-analyze/visitors/shared/a11y.js
@@ -875,7 +875,9 @@ export function check_element(node, context) {
 		}

 		// no-autofocus
-		if (name === 'autofocus') {
+		// `autofocus` is generally discouraged because it can be disruptive, but the HTML
+		// spec explicitly recommends it for <dialog> (or its descendants) when opening.
+		if (name === 'autofocus' && node.name !== 'dialog') {
 			w.a11y_autofocus(attribute);
 		}

